import{_ as s,o as n,c as e,E as o}from"./chunks/framework.BRIYLu4C.js";const y=JSON.parse('{"title":"python 应用 docker 镜像瘦身小技巧","description":"","frontmatter":{"title":"python 应用 docker 镜像瘦身小技巧","date":"2025-03-05T17:03:47.000Z","excerpt":"","tags":[],"categories":["还没有分类"]},"headers":[],"relativePath":"posts/python-应用-docker-镜像瘦身小技巧.md","filePath":"posts/python-应用-docker-镜像瘦身小技巧.md","lastUpdated":null}'),l={name:"posts/python-应用-docker-镜像瘦身小技巧.md"};function p(t,a,c,r,i,d){return n(),e("div",null,[...a[0]||(a[0]=[o(`<h2 id="正文" tabindex="-1">正文 <a class="header-anchor" href="#正文" aria-label="Permalink to &quot;正文&quot;">​</a></h2><p>在容器化 Python 应用时，Docker 镜像的大小直接影响部署效率、存储成本和传输速度。为了优化这些方面，我们可以通过一些技巧来显著减小 Docker 镜像的体积。以下是一些实用的瘦身小技巧：</p><h3 id="_1-使用精简的基础镜像" tabindex="-1">1. 使用精简的基础镜像 <a class="header-anchor" href="#_1-使用精简的基础镜像" aria-label="Permalink to &quot;1. 使用精简的基础镜像&quot;">​</a></h3><p>选择合适的基础镜像是减小 Docker 镜像大小的第一步。对于 Python 应用，推荐使用 <code>python:3.x-slim</code> 或 <code>python:3.x-alpine</code> 这样的轻量级镜像。例如，<code>python:3.9-slim</code> 镜像的大小约为 60 MB，而 <code>python:3.9-alpine</code> 镜像仅 23 MB，比基于 Ubuntu 的镜像小得多。</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">FROM</span><span style="color:#24292E;"> python:3.9-slim</span></span></code></pre></div><h3 id="_2-多阶段构建" tabindex="-1">2. 多阶段构建 <a class="header-anchor" href="#_2-多阶段构建" aria-label="Permalink to &quot;2. 多阶段构建&quot;">​</a></h3><p>多阶段构建是 Docker 中的一个强大特性，它允许你在一个阶段中构建应用，并在另一个阶段中运行应用，从而只保留必要的文件。这种方法可以显著减小最终镜像的大小。</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># 构建阶段</span></span>
<span class="line"><span style="color:#D73A49;">FROM</span><span style="color:#24292E;"> python:3.9-slim </span><span style="color:#D73A49;">AS</span><span style="color:#24292E;"> builder</span></span>
<span class="line"><span style="color:#D73A49;">WORKDIR</span><span style="color:#24292E;"> /app</span></span>
<span class="line"><span style="color:#D73A49;">COPY</span><span style="color:#24292E;"> requirements.txt .</span></span>
<span class="line"><span style="color:#D73A49;">RUN</span><span style="color:#24292E;"> pip install --no-cache-dir -r requirements.txt</span></span>
<span class="line"><span style="color:#D73A49;">COPY</span><span style="color:#24292E;"> . .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># 运行阶段</span></span>
<span class="line"><span style="color:#D73A49;">FROM</span><span style="color:#24292E;"> python:3.9-slim</span></span>
<span class="line"><span style="color:#D73A49;">WORKDIR</span><span style="color:#24292E;"> /app</span></span>
<span class="line"><span style="color:#D73A49;">COPY</span><span style="color:#24292E;"> --from=builder /app /app</span></span>
<span class="line"><span style="color:#D73A49;">CMD</span><span style="color:#24292E;"> [</span><span style="color:#032F62;">&quot;python&quot;</span><span style="color:#24292E;">, </span><span style="color:#032F62;">&quot;app.py&quot;</span><span style="color:#24292E;">]</span></span></code></pre></div><h3 id="_3-减少镜像层数" tabindex="-1">3. 减少镜像层数 <a class="header-anchor" href="#_3-减少镜像层数" aria-label="Permalink to &quot;3. 减少镜像层数&quot;">​</a></h3><p>每个 Dockerfile 指令（如 <code>RUN</code>）都会创建一个新的镜像层。通过将多个命令合并成一个 <code>RUN</code> 指令，可以减少镜像层数，从而减小镜像大小。</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">RUN</span><span style="color:#24292E;"> apt-get update &amp;&amp; apt-get install -y \\</span></span>
<span class="line"><span style="color:#24292E;">    build-essential \\</span></span>
<span class="line"><span style="color:#24292E;">    gcc \\</span></span>
<span class="line"><span style="color:#24292E;">    &amp;&amp; rm -rf /var/lib/apt/lists/*</span></span></code></pre></div><h3 id="_4-使用-dockerignore-文件" tabindex="-1">4. 使用 <code>.dockerignore</code> 文件 <a class="header-anchor" href="#_4-使用-dockerignore-文件" aria-label="Permalink to &quot;4. 使用 \`.dockerignore\` 文件&quot;">​</a></h3><p><code>.dockerignore</code> 文件可以排除不必要的文件和目录，避免它们被复制到 Docker 镜像中。这有助于减小镜像大小并加快构建速度。</p><div class="language-plaintext"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span># .dockerignore 文件示例</span></span>
<span class="line"><span>.git</span></span>
<span class="line"><span>__pycache__</span></span>
<span class="line"><span>*.log</span></span></code></pre></div><h3 id="_5-清理缓存和临时文件" tabindex="-1">5. 清理缓存和临时文件 <a class="header-anchor" href="#_5-清理缓存和临时文件" aria-label="Permalink to &quot;5. 清理缓存和临时文件&quot;">​</a></h3><p>在安装依赖后，及时清理缓存和临时文件可以进一步减小镜像大小。例如，在安装 Python 依赖后，可以使用 <code>rm -rf /root/.cache/pip</code> 来清理 pip 缓存。</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">RUN</span><span style="color:#24292E;"> pip install --no-cache-dir -r requirements.txt &amp;&amp; \\</span></span>
<span class="line"><span style="color:#24292E;">    rm -rf /root/.cache/pip</span></span></code></pre></div><h4 id="_6-使用-no-install-recommends-标志" tabindex="-1">6. 使用 <code>--no-install-recommends</code> 标志 <a class="header-anchor" href="#_6-使用-no-install-recommends-标志" aria-label="Permalink to &quot;6. 使用 \`--no-install-recommends\` 标志&quot;">​</a></h4><p>在安装系统包时，使用 <code>--no-install-recommends</code> 标志可以避免安装不必要的推荐包，从而减小镜像大小。</p><div class="language-dockerfile"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">RUN</span><span style="color:#24292E;"> apt-get update &amp;&amp; apt-get install -y --no-install-recommends \\</span></span>
<span class="line"><span style="color:#24292E;">    curl \\</span></span>
<span class="line"><span style="color:#24292E;">    unzip \\</span></span>
<span class="line"><span style="color:#24292E;">    &amp;&amp; rm -rf /var/lib/apt/lists/*</span></span></code></pre></div><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>无</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>无</p>`,24)])])}const u=s(l,[["render",p]]);export{y as __pageData,u as default};
